SELECT recipient_type, COUNT(recipient_id) AS number_of_recipients
FROM recipients
GROUP BY recipient_type;

SELECT COUNT(DISTINCT recipient_id) 
FROM recipient_percentiles 
WHERE percentile_range = 'Top 2%';

SELECT percentile_range, SUM(number_of_recipients) AS total_recipients
FROM payment_distributions
GROUP BY percentile_range;

SELECT percentile_range, percentage_of_payments
FROM payment_distributions
ORDER BY percentage_of_payments DESC;

SELECT AVG(number_of_recipients) AS average_recipients_in_top_2_percent
FROM payment_distributions
WHERE percentile_range = 'Top 2%';

SELECT COUNT(recipient_id) AS number_of_top_1_percent_recipients
FROM recipient_percentiles
WHERE percentile_range = 'Top 1%';
